import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
"21": {
"1": "<p>YHWH commands Ezekiel to set his face toward Jerusalem and prophesy against the sanctuaries. Christ is the temple that replaced the Jerusalem sanctuary (John 2:19-21); his body is the true meeting place between God and humanity, and judgment that fell on the old sanctuary system was resolved at the cross.</p>",
"2": "<p>The word goes against the land of Israel. Christ is the Word made flesh who bore the full weight of divine speech against a rebellious people (John 1:14; Heb 1:1-2); what prophets proclaimed in words, Christ enacted in his body.</p>",
"3": "<p>YHWH declares he will cut off both the righteous and the wicked — a shocking statement resolved only in Christ. The sword of judgment that cannot discriminate among sinners fell with full force on the sinless Son (2 Cor 5:21), who took the undiscriminating blow so that genuine righteousness might be distinguished in him (Rom 3:25-26).</p>",
"4": "<p>All flesh from south to north will know YHWH has drawn his sword. The universal scope of judgment — no flesh exempt — finds its resolution in the cross, where Christ stood as substitute for all flesh (1 Pet 3:18; 1 John 2:2). The sword unsheathed against all becomes the spear that pierces the one (John 19:34).</p>",
"5": "<p>The sword will not return to its sheath. The finality of divine judgment, once drawn, points to the finality of Christ's atoning work — the sword satisfied, sheathed permanently at the resurrection (Rom 4:25). The debt fully paid requires no further drawing.</p>",
"6": "<p>Ezekiel is told to groan with breaking heart. Christ groaned in the garden (Luke 22:44) and wept at Lazarus's tomb (John 11:35) — the divine grief over sin and death that Ezekiel enacted in symbol became embodied anguish in the Son.</p>",
"7": "<p>When the people ask why Ezekiel groans, he is to say it is for the news that is coming. Christ announced his own passion three times (Luke 9:22; 18:31-33; 22:37) — not as passive victim but as one who understood the full weight of what was coming and moved toward it with deliberate intent.</p>",
"8": "<p>The sword sharpened and polished — ready for slaughter. The instrument of judgment prepared with precision points to the purposefulness of the cross: Christ was not accidentally crucified but delivered up by the definite plan of God (Acts 2:23), the sword prepared from eternity.</p>",
"9": "<p>The sharpened sword consumes all who despise judgment. Christ absorbed the consuming judgment (Heb 12:29; Deut 4:24) so that those who trust him face the consuming fire not as enemies but as those purified by the Refiner (Mal 3:3).</p>",
"10": "<p>The sword polished to flash like lightning. At Christ's return the Son of Man comes with lightning-like power (Matt 24:27), the same divine sword now wielded in final vindication rather than atoning sacrifice. The polished blade appears twice — once at Calvary, once at the end.</p>",
"11": "<p>The sword given into the hand of the slayer. YHWH himself delivers the instrument into human hands — as Christ was handed over to Pilate and crucifiers by divine permission (John 19:11; Acts 4:27-28). God did not lose control; he directed the very act of his Son's death.</p>",
"12": "<p>Ezekiel is told to cry and wail, smiting his thigh. The prophetic mourning for Israel's judgment prefigures the grief of holy witnesses at the cross — the women of Jerusalem (Luke 23:27-28), the beloved disciple, the centurion who confessed. Grief and confession are the right responses to this judgment.</p>",
"13": "<p>Testing: if the sword despises even the scepter, what then? The crisis of all human authority — scepter, throne, law — is that it cannot survive the sword of divine justice. Christ the King laid down his scepter in Gethsemane (Phil 2:7-8), submitting to the sword so that his kingship might be established through resurrection rather than force.</p>",
"14": "<p>Prophesy and clap your hands; let the sword strike twice, even three times. The triple blow echoes the three days in the tomb and the fullness of judgment exhausted. Christ died once for sins, the righteous for the unrighteous (1 Pet 3:18), but the triple strike signals completeness — nothing remains of the debt.</p>",
"15": "<p>The sword is at every gate, made to glitter and wrapped for slaughter. No exit from judgment — every gate guarded. Christ's resurrection opens the gate that no sword can permanently seal (Acts 2:24; Rev 1:18 — he holds the keys of death and Hades).</p>",
"16": "<p>The sword cuts on both sides — right and left — no escape. The universal reach of divine justice is matched by the universal reach of Christ's atonement (1 Tim 2:6; 1 John 2:2). The same comprehensive coverage that made judgment inescapable makes grace equally comprehensive for those in Christ.</p>",
"17": "<p>YHWH himself will clap his hands and let his fury rest. The resting of divine fury is what Paul calls the propitiation (hilasterion, Rom 3:25) — YHWH's wrath fully expressed and fully satisfied at the cross, not suppressed but exhausted in the Son.</p>",
"18": "<p>The word of YHWH directing Ezekiel to mark two roads for the Babylonian sword — a parable of divine sovereignty choosing routes of judgment. Christ is the one true way (John 14:6) on which the fork of condemnation and salvation divides; those in him take the road of life.</p>",
"19": "<p>The two roads lead to Jerusalem and to Rabbah of Ammon — YHWH's judgment is geographically comprehensive. Christ's cross stands at the intersection where all roads of human rebellion converge (Col 2:14-15), absorbing the sentence carried on every path.</p>",
"20": "<p>Babylon stood at the road's fork using divination — arrows, teraphim, liver — to choose the path. Christ supersedes all forms of seeking divine guidance through ritual or magic (Col 2:8; 1 Cor 1:22-24); he is himself the wisdom of God, no divination needed.</p>",
"21": "<p>The right hand of Babylon chose Jerusalem for the battering ram. Kingdoms are instruments of YHWH's purpose even when they do not know it (Isa 10:5-7). Pilate, Herod, and Rome similarly served as unwitting instruments in the crucifixion, their authority subordinate to the divine plan (Acts 4:27-28).</p>",
"22": "<p>The divination false to those who swore oaths to Babylon — yet it will bring the iniquity to remembrance. The accumulated iniquity that forced judgment is what the cross addresses — Christ bearing remembered iniquities to their final reckoning so they are remembered no more (Heb 8:12; Jer 31:34).</p>",
"23": "<p>To Jerusalem it is a lying divination in their sight — they will be captured. Human self-deception about divine favor, assuming safety when judgment is already determined. Christ warned Jerusalem with grief (Matt 23:37-38) against this same fatal self-confidence; the stone of stumbling is also the cornerstone (1 Pet 2:6-8).</p>",
"24": "<p>Because Jerusalem brought its guilt to remembrance and its transgressions uncovered — it shall be taken by the hand. Exposure and capture: the cross is the ultimate exposure of human guilt and simultaneously its resolution. What was uncovered was covered (atoned) by Christ's body (1 Pet 2:24).</p>",
"25": "<p>To the profane and wicked prince of Israel — his day of final punishment. The corrupt prince who distorts justice stands in contrast to Christ the Prince of Peace (Isa 9:6) who establishes justice by bearing injustice (Isa 53:8; Acts 8:33).</p>",
"26": "<p>Remove the turban, take off the crown — the things overturned; lowly exalted and high abased. This radical inversion is the pattern of Christ's kingdom — the Beatitudes, Mary's Magnificat (Luke 1:52), and the cross itself where the crowned King wore thorns (John 19:2). What was high (self-reliant Israel) is brought low; what was low (the suffering servant) is exalted.</p>",
"27": "<p>Overthrow, overthrow, overthrow — a ruin unlike any before, until he comes whose right it is (shelo hammishpat). This triple overthrow and messianic pause is one of the clearest pre-exilic messianic markers in the prophets. The chaos of judgment will not be resolved until the one whose rightful claim on the throne arrives. Genesis 49:10 uses parallel language (shiloh); Luke 1:32-33 identifies Christ as receiving the throne of his father David; Revelation 19:16 as King of kings. All history between Ezekiel and the eschaton is the time of the triple overthrow, awaiting the Rightful One.</p>",
"28": "<p>The sword against Ammon — prophesy against them. Judgment extends beyond Israel to all nations. Christ is appointed judge of all peoples (Acts 17:31); his death purchases people from every nation, tribe, and tongue (Rev 5:9), so that the universal scope of judgment corresponds to the universal scope of redemption.</p>",
"29": "<p>The sword drawn for slaughter — polished to consume, to flash like lightning. The eschatological sword that Christ wields at his return (Rev 19:15 — a sharp sword from his mouth) consumes what the cross did not forgive. The two appearances of the sword divide redemptive history.</p>",
"30": "<p>The sword returned to its sheath in Ammon's place — judged there. Divine judgment executed in its proper place and time. The cross was the predetermined place and time (kairos) where divine judgment was properly executed — not arbitrary, but precisely appointed (Acts 2:23; Gal 4:4).</p>",
"31": "<p>Pour out your indignation on Ammon — pour out your wrath on the nations. The wrath poured out on the nations at the end is what was poured out on the Son at the cross (Isa 53:12; Rom 5:9) — those who receive Christ's shelter escape the final outpouring.</p>",
"32": "<p>Ammon will be forgotten — no more remembered. The nations that opposed God will be forgotten, while those in Christ are remembered in the Book of Life (Rev 20:15). The forgotten name versus the name written in heaven — the contrast the cross creates.</p>"
},
"22": {
"1": "<p>The word of YHWH comes to Ezekiel again. The persistent, relentless nature of divine speech — even after judgment is pronounced — mirrors Christ's perseverance in calling his people. He who spoke through prophets ultimately spoke in the Son (Heb 1:1-2), the final and definitive word.</p>",
"2": "<p>Will you judge the bloody city? Declare to her all her abominations. The prophetic call to declare sin precedes the announcement of grace. Christ did not shy from declaring sin's seriousness — the Sermon on the Mount, the woes against the Pharisees, the cleansing of the temple (Matt 21:12-13) — because grace requires an honest diagnosis.</p>",
"3": "<p>Jerusalem shed blood in her midst — her time has come. The city that shed blood faces her own bloody judgment. Christ entered the city knowing she would shed his blood (Matt 16:21; Luke 13:33-34); his was the innocent blood that brought both the ultimate judgment on Jerusalem (Matt 23:35-36; Luke 21:20-24) and the atonement for all blood-guilt.</p>",
"4": "<p>Guilty in your own blood — defiled by your idols — your day has drawn near. Guilt that accelerates toward its own reckoning. The cross is where human guilt reached its fullest expression (the crucifixion of the Son of God) and simultaneously its resolution — Christ made guilty by imputation so those in him are declared not guilty (2 Cor 5:21).</p>",
"5": "<p>Those near and far will mock the infamous, defiled city. The mockery surrounding Jerusalem's fall — neighbors taunting the fallen city — directly prefigures the mockery at the cross (Matt 27:39-44). Christ absorbed the shame and mockery that was Israel's due, becoming a curse for us (Gal 3:13).</p>",
"6": "<p>Each prince of Israel used his arm to shed blood. The leaders responsible for bloodshed find their counterpart in the rulers who condemned Christ — Pilate, Herod, the chief priests (Acts 4:27-28). All human authority complicit in the unjust shedding of blood, yet all within the divine plan.</p>",
"7": "<p>Father and mother dishonored, sojourner oppressed, orphan and widow wronged. The exploitation of the vulnerable is reversed in Christ who championed the outcast (Luke 4:18-19; Matt 5:3-10), who himself became the ultimate sojourner — having nowhere to lay his head (Matt 8:20) — and identified with the oppressed.</p>",
"8": "<p>My holy things despised, my sabbaths profaned. The profaning of sacred time and space that characterized Jerusalem's sin is healed by Christ who is himself Lord of the sabbath (Mark 2:28) and the true holy place (John 2:21). In him the sabbath rest is not profaned but fulfilled (Heb 4:9-10).</p>",
"9": "<p>Slanderers in your midst to shed blood; idolaters on the mountains eating. The social breakdown — slander, idolatry, immorality — that makes Jerusalem a bloody city is the disorder Christ came to heal. His kingdom reorders human community around truth (John 14:6), worship of the Father (John 4:23-24), and the ethics of the Sermon on the Mount.</p>",
"10": "<p>The uncovering of nakedness within kin — violations of holiness laws. The pervasive sexual and social transgression points to a deep disorder in covenant relationship with God. Christ restores the honor and dignity of the human body — made in God's image — by taking on flesh and redeeming it through the resurrection (1 Cor 6:19-20; Phil 3:21).</p>",
"11": "<p>Abomination with neighbor's wife, defiling daughter-in-law, violating sister. The comprehensive list of covenantal violations within the family — the most intimate sphere of human life. Christ restores intimacy and fidelity through the new covenant sealed in his blood (Luke 22:20), making his people a holy family (Eph 1:5; 2:19).</p>",
"12": "<p>Bribes for blood, interest and usury taken, extorting neighbors, forgetting YHWH. The economic sins — exploiting the vulnerable financially — stand condemned. Christ drives out those who have made the house of prayer a den of thieves (Matt 21:13); the kingdom economy reverses exploitation with generosity, usury with gift (Luke 6:35).</p>",
"13": "<p>YHWH claps his hands at the dishonest gain and bloodshed. Divine indignation at human injustice is not indifference — God takes exploitation of the poor personally (Prov 19:17; Matt 25:40). Christ identifies himself with the poor and exploited; their cause is his cause.</p>",
"14": "<p>Can your heart endure or your hands be strong in the day YHWH deals with you? The day of reckoning that no human fortitude can survive is what Christ faced alone at Golgotha — forsaken, weakened, condemned — so that those in him might stand on that day (Rom 5:9; 1 Thess 1:10).</p>",
"15": "<p>YHWH will scatter Israel among the nations and remove her uncleanness. The scattering that is judgment becomes, in Christ, the gathering of the scattered children of God (John 11:52). Pentecost reverses Babel; the ingathering of the nations becomes the fulfillment of Israel's purification.</p>",
"16": "<p>Jerusalem shall be profaned in the sight of the nations — and know YHWH. Humiliation leading to knowledge of God: the pattern of the cross. Christ humiliated himself — taking the form of a servant, obedient to death on a cross (Phil 2:7-8) — so that at his name every knee would bow and every tongue confess (Phil 2:10-11).</p>",
"17": "<p>The word of YHWH — Israel has become dross to me. The smelting metaphor introduces Israel as the waste product of a refining process — dross, not silver. This is the nadir of covenant relationship: the people meant to be a kingdom of priests have become slag.</p>",
"18": "<p>All of them are bronze, tin, iron, and lead — dross in the furnace, not silver. The indiscriminate mixture of base metals signals the thorough corruption of the covenant community. Christ as the Refiner (Mal 3:3) entered this dross-filled furnace himself — born into a corrupt Israel — to separate the precious from the worthless through his atoning death (1 Pet 1:18-19).</p>",
"19": "<p>Because you have become dross, gather you into Jerusalem. The gathering into the city precedes the smelting judgment. Christ gathered his followers in Jerusalem precisely where the judgment-furnace of the cross would burn (Luke 13:33). The city became the furnace.</p>",
"20": "<p>As silver, bronze, iron, lead, and tin are gathered into the furnace to blow fire on them, so I will gather and blow with my wrath. The comprehensive metaphor of smelting — all metals in — parallels the cross where the full wrath of God against all sin was poured out (Rom 3:25; 1 John 2:2). Christ endured the full blast of the divine furnace.</p>",
"21": "<p>YHWH will gather and blow with his fire of wrath — you will be melted in it. The total melting — dissolution of all pretense and self-sufficiency — is what the cross accomplished for Christ. He who knew no sin became sin (2 Cor 5:21), fully subjected to the fire, so that from the furnace emerges the pure silver of a justified people (Zech 13:9).</p>",
"22": "<p>As silver is melted in a furnace, so you will be melted in the midst of the city — and know that YHWH has poured out his wrath. The smelting that produces knowledge of God: Christ's cross is the furnace that produced the purest revelation of both divine wrath against sin and divine love for sinners (John 3:16; Rom 5:8). No fuller revelation of either exists.</p>",
"23": "<p>The land has not been cleansed, not rained upon in the day of indignation. The absence of cleansing rain mirrors spiritual drought — the land under judgment is dry, unfruitful. Christ is the living water (John 4:14; 7:37-38) who ends the drought; his Spirit poured out like rain (Joel 2:28-29; Acts 2:17-18) cleanses what the furnace refines.</p>",
"24": "<p>Her prophets conspired within her — devouring souls, taking treasure, multiplying widows. The false prophets who exploit for personal gain stand in sharpest contrast to Christ the true prophet who gave his life rather than taking others (Mark 10:45). He is the prophet whose word is spirit and life (John 6:63), not a word crafted for wealth.</p>",
"25": "<p>Her priests violated YHWH's law, profaned his holy things, did not distinguish holy from common, hid their eyes from the sabbath. The priests who failed the holy/common distinction point to the crisis of priesthood. Christ the great high priest perfectly distinguishes — holy in himself (Heb 7:26), who by his own blood makes access to the holy of holies permanent and complete (Heb 10:19-22).</p>",
"26": "<p>Her princes are like wolves tearing prey — shedding blood, destroying lives for dishonest gain. The wolf-princes contrast with Christ the Good Shepherd who gives his life for the sheep rather than destroying them for gain (John 10:11-13). The false shepherds-turned-wolves become the context that makes the Good Shepherd's self-sacrifice so radical.</p>",
"27": "<p>Her prophets plastered over with whitewash — seeing false visions, lying divinations, saying thus says the Lord when YHWH has not spoken. The false prophets who smooth over sin with comfortable lies contrast with Christ who refused to whitewash — confronting sin directly in himself as the sin-bearer (1 Pet 2:24) and calling his disciples to truth even when costly (John 8:32).</p>",
"28": "<p>The people of the land practiced extortion and committed robbery — they oppressed the poor. The complete moral failure across every class of society — princes, priests, prophets, people — demonstrates that no human reform from within the system could save it. Only an intervention from outside — a new Adam, a new covenant, a new humanity in Christ — could address the systemic failure (Rom 8:3-4).</p>",
"29": "<p>I sought for a man among them who should build up the wall and stand in the breach before me for the land, that I should not destroy it — but I found no one. This verse is the theological heart of the chapter and one of the most pregnant silences in the Old Testament. YHWH searched for a human mediator-intercessor and found none. The failure of every human candidate — prophet, priest, prince, and people — creates the void that only the incarnate Son can fill. Christ is precisely the one who stands in the breach: his cross is the wall-building and breach-standing that v.30 demands (Heb 7:25 — he always lives to intercede; Rom 8:34 — Christ intercedes for us; Rom 5:8 — while we were still sinners, God provided what no human could). The not-found-anyone of Ezekiel 22:30 is answered by the God-himself-will-provide of the gospel.</p>",
"30": "<p>YHWH poured out his indignation on Israel and consumed them with the fire of his wrath. The destruction that came because no mediator was found points forward to the one mediator between God and humanity, the man Christ Jesus (1 Tim 2:5), who was consumed by the fire of wrath at the cross so that the land — the new creation (Rev 21-22) — would not be destroyed but renewed.</p>",
"31": "<p>Their way returned on their own heads — declares the Lord YHWH. The principle of recompense — deeds returning on the doer — is what the cross reverses for believers. Christ took on himself the returning of our own way (Gal 3:13; Isa 53:6 — the LORD laid on him the iniquity of us all). The boomerang of judgment that Ezekiel 22:31 describes lands on the Son so that those in him escape it.</p>"
}
}

existing = load_comm("mkt-christ", "ezekiel")
merge_comm(existing, NEW_DATA)
save_comm("mkt-christ", "ezekiel", existing)

# Verify
interlinear = json.loads((ROOT / 'data' / 'interlinear' / 'ezekiel.json').read_text())
for ch, expected_count in [("21", 32), ("22", 31)]:
    have = len(existing.get(ch, {}))
    total = len(interlinear.get(ch, {}))
    status = "complete" if have >= total else f"MISSING {total - have}"
    print(f"ch {ch}: {status} ({have} verses)")

print("All verses present" if all(
    len(existing.get(ch, {})) >= len(interlinear.get(ch, {}))
    for ch in ["21", "22"]
) else "WARNING: missing verses")
